/**
 * @param {number} n The number of rows.
 * @param {number} m The number of columns.
 * @param {number[][]} sources An array where sources[i] = [r_i, c_i, color_i].
 * @returns {number[][]} The final state of the grid.
 */
function solve(n, m, sources) {
    // Initialize the grid with 0 (uncolored)
    const grid = Array(n).fill(0).map(() => Array(m).fill(0));

    // A queue for BFS. Each element is [r, c, time, color].
    // time here represents the shortest distance from any source.
    // Since we are prioritizing higher colors in case of a tie in time,
    // we will use a priority queue approach implicitly by processing based on time,
    // and handling color conflicts when updating the grid.

    // A better approach for this problem, where we care about the MIN time to reach a cell
    // and MAX color for that minimum time, is to use a Multi-Source BFS.
    // The queue will store [time, color, r, c].

    const pq = []; // Min-Heap simulation: [time, -color, r, c]

    // For each source, push to PQ. We use negative color because we want the *smallest* time,
    // and for equal times, the *largest* color. In a min-heap, smaller values are prioritized.
    // So, smaller -color means larger color.
    for (const [r, c, color] of sources) {
        // Initial time is 0, initial color is 'color'
        pq.push([0, -color, r, c]);
        // Mark the source cell immediately with its color.
        // We need a way to track the best known state for each cell.
        grid[r][c] = color; 
    }

    // Custom Priority Queue implementation for this specific structure (Min-Heap on time, then Max-Heap on color)
    // Since JavaScript doesn't have a built-in Priority Queue, we'll use a simple array sort approach
    // which might be slow but is easier to implement correctly for competitive programming style,
    // given N*M <= 10^5. A full heap implementation is complex but necessary for strict complexity.
    // Given the constraints, the total number of elements pushed to the queue is at most N*M.

    // Let's simulate a PQ by always sorting/finding the minimum element.

    while (pq.length > 0) {
        // Find the element with the minimum time. If times are equal, find the one with the maximum color (minimum -color).
        pq.sort((a, b) => {
            if (a[0] !== b[0]) {
                return a[0] - b[0]; // Sort by time ascending (Min-Heap on time)
            }
            return a[1] - b[1]; // Sort by -color ascending, which means color descending (Max-Heap on color)
        });

        const [time, negColor, r, c] = pq.shift();
        const color = -negColor;

        // Check if this state is obsolete.
        // If the current recorded color in the grid is greater than the color we just pulled,
        // or if the time taken to reach the cell recorded in the grid is less than or equal to 'time'
        // (this logic is complex because we are propagating, not just relaxing edges like Dijkstra).

        // The key insight for this specific problem (Max Color on Tie) is:
        // A cell (r, c) should retain the color associated with the shortest time.
        // If multiple colors arrive at the shortest time, it keeps the maximum color.
        // If a cell is already colored, and the incoming time is greater than the time it was colored, ignore it.
        // If the incoming time is equal to the time it was colored, only update if the incoming color is greater.

        // Since we initialized grid[r][c] = color for sources (time 0),
        // we must ensure we don't re-process a cell if it has already been finalized with a better (time, color) pair.

        // To correctly handle this, we need to store [min_time, max_color] for each cell, not just the color.

        // Let's restart the state tracking to be more explicit about (time, color) dominance.
    }

    // --- Re-implementation using explicit tracking of (time, color) dominance ---

    // Initialize grid: stores {time: Infinity, color: 0}
    const state = Array(n).fill(0).map(() => Array(m).fill(null).map(() => ({ time: Infinity, color: 0 })));

    // Priority Queue: [time, -color, r, c]
    const pq_v2 = [];

    for (const [r, c, color] of sources) {
        state[r][c] = { time: 0, color: color };
        // Push to PQ: [time, -color, r, c]
        pq_v2.push([0, -color, r, c]);
    }

    // Min-Heap simulation (sorting on every extraction)
    while (pq_v2.length > 0) {
        // Sort to get min time, then max color
        pq_v2.sort((a, b) => {
            if (a[0] !== b[0]) {
                return a[0] - b[0]; // Min time
            }
            return a[1] - b[1]; // Max color (-color ascending)
        });

        const [time, negColor, r, c] = pq_v2.shift();
        const color = -negColor;

        // Check for dominance: If the state we pulled from the queue is worse than the current recorded state, skip.
        // Worse means: greater time, OR (equal time AND smaller color).
        if (time > state[r][c].time || (time === state[r][c].time && color < state[r][c].color)) {
            continue;
        }

        // Explore neighbors
        const directions = [[0, 1], [0, -1], [1, 0], [-1, 0]];

        for (const [dr, dc] of directions) {
            const nr = r + dr;
            const nc = c + dc;

            if (nr >= 0 && nr < n && nc >= 0 && nc < m) {
                const newTime = time + 1;
                const newColor = color;

                const currentState = state[nr][nc];

                // Determine if this new path (newTime, newColor) is better than the current state at (nr, nc)

                let shouldUpdate = false;

                if (newTime < currentState.time) {
                    // Strictly faster arrival time is always better
                    shouldUpdate = true;
                } else if (newTime === currentState.time) {
                    // Same arrival time, check for maximum color
                    if (newColor > currentState.color) {
                        shouldUpdate = true;
                    }
                }
                // If newTime > currentState.time, it's worse, so we don't update.

                if (shouldUpdate) {
                    state[nr][nc].time = newTime;
                    state[nr][nc].color = newColor;

                    // Add the updated cell to the PQ
                    pq_v2.push([newTime, -newColor, nr, nc]);
                }
            }
        }
    }

    // Format the result back into the required 2D array of colors
    const result = Array(n).fill(0).map(() => Array(m).fill(0));
    for (let r = 0; r < n; r++) {
        for (let c = 0; c < m; c++) {
            result[r][c] = state[r][c].color;
        }
    }

    return result;
}

