import java.util.PriorityQueue

fun solve(n: Long, m: Long, sources: Array<Array<Long>>): Array<Array<Long>> {
    val N = n.toInt()
    val M = m.toInt()

    // State tracking for each cell: [min_time, max_color]
    // Initialize time to a very large value (infinity) and color to 0.
    val state = Array(N) { Array(M) { Pair(Long.MAX_VALUE, 0L) } }

    // Priority Queue: Stores [time, -color, r, c].
    // We want a Min-Heap based on time. If times are equal, we want a Max-Heap based on color.
    // By storing -color, a smaller value in the heap corresponds to a larger color.
    val pq = java.util.PriorityQueue<Triple<Long, Long, Pair<Int, Int>>>()

    // Helper class/data structure to represent PQ element for clarity, though Triple works if we define the comparator correctly
    // Let's use a custom structure or comparator for the PQ.
    data class StateItem(val time: Long, val negColor: Long, val r: Int, val c: Int) : Comparable<StateItem> {
        override fun compareTo(other: StateItem): Int {
            // Compare time (Min-Heap)
            val timeCompare = this.time.compareTo(other.time)
            if (timeCompare != 0) return timeCompare
            // Compare negColor (Min-Heap on negColor => Max-Heap on color)
            return this.negColor.compareTo(other.negColor)
        }
    }

    val pq_custom = PriorityQueue<StateItem>()

    // Initialize sources
    for (source in sources) {
        val r = source[0].toInt()
        val c = source[1].toInt()
        val color = source[2]

        // Initial state: time 0, color 'color'
        state[r][c] = Pair(0L, color)
        pq_custom.add(StateItem(0L, -color, r, c))
    }

    val directions = arrayOf(intArrayOf(0, 1), intArrayOf(0, -1), intArrayOf(1, 0), intArrayOf(-1, 0))

    while (pq_custom.isNotEmpty()) {
        val current = pq_custom.poll()
        val time = current.time
        val color = -current.negColor
        val r = current.r
        val c = current.c

        // Check for dominance: If the state we pulled from the queue is worse than the current recorded state, skip.
        val (recordedTime, recordedColor) = state[r][c]
        if (time > recordedTime || (time == recordedTime && color < recordedColor)) {
            continue
        }

        // Explore neighbors
        for ((dr, dc) in directions) {
            val nr = r + dr
            val nc = c + dc

            if (nr in 0 until N && nc in 0 until M) {
                val newTime = time + 1
                val newColor = color

                val (currentStateTime, currentStateColor) = state[nr][nc]

                var shouldUpdate = false

                if (newTime < currentStateTime) {
                    // Strictly faster arrival time is always better
                    shouldUpdate = true
                } else if (newTime == currentStateTime) {
                    // Same arrival time, check for maximum color
                    if (newColor > currentStateColor) {
                        shouldUpdate = true
                    }
                }
                // If newTime > currentStateTime, it's worse, so we don't update.

                if (shouldUpdate) {
                    state[nr][nc] = Pair(newTime, newColor)

                    // Add the updated cell to the PQ
                    pq_custom.add(StateItem(newTime, -newColor, nr, nc))
                }
            }
        }
    }

    // Format the result back into the required 2D array of colors
    val result = Array(N) { Array(M) { 0L } }
    for (r in 0 until N) {
        for (c in 0 until M) {
            result[r][c] = state[r][c].second
        }
    }

    return result
}
