fun solve(n: Long, m: Long, sources: Array<Array<Long>>): Array<Array<Long>> {
    // Use Long for grid dimensions to match signature, but cast to Int for array indexing if within limits (N*M <= 10^5)
    val N = n.toInt()
    val M = m.toInt()

    // State tracking: {time, color} for each cell. Initialized to Infinity time and 0 color.
    data class CellState(var time: Int, var color: Int)

    val state = Array(N) { Array(M) { CellState(Int.MAX_VALUE, 0) } }

    // Priority Queue for Multi-Source BFS (Dijkstra-like approach)
    // We prioritize:
    // 1. Minimum time (smaller time is better)
    // 2. Maximum color (larger color is better for ties in time)
    // PQ elements: [time, -color, r, c]
    // Using negative color ensures that when times are equal, the PQ extracts the smallest -color, which corresponds to the largest color.
    val pq = PriorityQueue<IntArray>(compareBy<IntArray> { it[0] }.thenBy { it[1] })

    for (source in sources) {
        val r = source[0].toInt()
        val c = source[1].toInt()
        val color = source[2].toInt()

        // Initialize source cell state
        state[r][c] = CellState(0, color)

        // Add to PQ
        pq.add(intArrayOf(0, -color, r, c))
    }

    val directions = arrayOf(intArrayOf(0, 1), intArrayOf(0, -1), intArrayOf(1, 0), intArrayOf(-1, 0))

    while (pq.isNotEmpty()) {
        val current = pq.poll()
        val time = current[0]
        val negColor = current[1]
        val r = current[2]
        val c = current[3]
        val color = -negColor

        // Check for obsolescence: If the state pulled from PQ is worse than the current recorded state, skip.
        // Worse means: greater time, OR (equal time AND smaller color).
        if (time > state[r][c].time || (time == state[r][c].time && color < state[r][c].color)) {
