    // We use an array/tuple representation in the PQ for simplicity with standard library implementation,
    // where element comparison dictates priority.
    data class PQElement(val time: Int, val negColor: Long, val r: Int, val c: Int) : Comparable<PQElement> {
        override fun compareTo(other: PQElement): Int {
            // 1. Compare time (ascending)
            if (this.time != other.time) {
                return this.time.compareTo(other.time)
            }
            // 2. Compare negColor (ascending, which means color descending)
            return this.negColor.compareTo(other.negColor)
        }
